const input = $input.item.json;
const body = input.body || input;

const event = body.event;
if (event !== 'atendimento_fechado') {
  return [{ json: { skip: true, reason: 'evento ignorado: ' + event } }];
}

const messages = body.messages || [];
if (messages.length === 0) {
  return [{ json: { skip: true, reason: 'sem mensagens' } }];
}

messages.sort((a, b) => new Date(a.sent_at) - new Date(b.sent_at));

let transcriptForAI = '';
const dbRecords = [];

for (const msg of messages) {
  const role = msg.role || 'BOT';
  const name = msg.sender_name || role;
  const content = msg.message_text || '';
  const mediaType = (msg.message_type || 'text').toUpperCase();
  const hasMedia = msg.has_media === true;

  let displayContent = content;
  if (hasMedia && msg.media_url) {
    const mediaNote = `[Midia: ${mediaType}]`;
    displayContent = content ? `${content} ${mediaNote}` : mediaNote;
  }

  const dateStr = msg.sent_at
    ? new Date(msg.sent_at).toLocaleString('pt-BR')
    : '';

  transcriptForAI += `[${dateStr}] **${name} (${role}):** ${displayContent}\n`;

  dbRecords.push({
    message_uid: msg.message_uid,
    chat_id: msg.chat_id,
    sent_at: msg.sent_at,
    sender_type: role,
    sender_name: name,
    raw_sender_type: msg.sender_type,
    text_content: content,
    has_media: hasMedia,
    media_url: msg.media_url || null,
    media_type: hasMedia ? mediaType : null,
    direction: msg.direction,
    origin: msg.origin
  });
}

return [{
  json: {
    skip: false,
    atendimento_id: body.atendimento_id,
    contact_id: body.contact_id,
    lead_id: body.lead_id,
    lead_nome: body.lead_nome,
    lead_telefone: body.lead_telefone,
    session_start: body.session_start,
    session_end: body.session_end,
    message_count: messages.length,
    chat_ids: body.chat_ids || [],
    transcript_ia: transcriptForAI,
    db_records: dbRecords
  }
}];

const item = $input.item.json;
const records = item.db_records || [];
const medias = records.filter(r => r.has_media === true);

if (medias.length === 0) {
  return [{ json: { media_count: 0, medias: [] } }];
}

const output = medias.map(m => ({
  message_uid: m.message_uid,
  sent_at: m.sent_at,
  media_type: m.media_type,
  media_url: m.media_url,
  sender_type: m.sender_type,
  sender_name: m.sender_name
}));

return [{ json: { media_count: output.length, medias: output } }];

const item = $input.item.json;
const medias = item.medias || [];

const grouped = {
  VOICE: [],
  VIDEO: [],
  FILE: [],
  PICTURE: []
};

for (const m of medias) {
  const tipo = (m.media_type || '').toUpperCase();
  if (grouped[tipo]) grouped[tipo].push(m);
}

const saida = [];
for (const tipo of Object.keys(grouped)) {
  if (grouped[tipo].length > 0) {
    saida.push({
      json: {
        media_type: tipo,
        count: grouped[tipo].length,
        messages: grouped[tipo]
      }
    });
  }
}

return saida.length > 0 ? saida : [{ json: { media_type: 'NONE', count: 0, messages: [] } }];

