const all = items.map(i => i.json);

const janela = all.find(o => o && o.db_records);
if (!janela) {
  return [{ json: { error: 'sem dados de janela', db_records: [] } }];
}

let dbRecords = (janela.db_records || []).slice();
dbRecords.sort((a, b) => new Date(a.sent_at) - new Date(b.sent_at));

const extrasAll = all.filter(o => !o.db_records && typeof o.text === 'string');

if (extrasAll.length > 0) {
  let idxExtra = 0;
  dbRecords = dbRecords.map(r => {
    const rec = { ...r };
    if (rec.has_media && rec.media_type && idxExtra < extrasAll.length) {
      rec.text_content = extrasAll[idxExtra].text;
      rec.has_media = false;
      rec.media_type = null;
      idxExtra++;
    }
    return rec;
  });
}

return [{ json: { ...janela, db_records: dbRecords } }];

const janela = $json;
const records = janela.db_records || [];

return records.map(r => ({
  json: {
    message_uid: r.message_uid,
    chat_id: r.chat_id,
    sender_type: r.sender_type,
    sender_name: r.sender_name,
    mensagem: r.text_content || '',
    message_at: r.sent_at,
    consultor_nome: r.sender_type === 'CONSULTOR' ? (r.sender_name || '') : null,
    direction: r.direction
  }
}));

const items = $input.all();

if (!items.length) {
  return [{ json: { conversa_bruta: '' } }];
}

const linhas = items.map(item => {
  const j = item.json;
  const role = j.sender_type || 'BOT';
  const name = (j.sender_name || '').trim();
  const consultor = (j.consultor_nome || '').trim();
  const msg = j.mensagem || '';
  const hora = j.message_at || '';

  let papel;
  if (role === 'CLIENTE') {
    papel = 'CLIENTE';
  } else if (role === 'CONSULTOR' && consultor) {
    papel = `CONSULTOR (${consultor})`;
  } else {
    papel = 'BOT';
  }

  return `[${hora}] ${papel}: ${msg}`;
});

return [{ json: { conversa_bruta: linhas.join('\n') } }];

const TAB_NODE = 'TABULACAO COMERCIAL';
const CONV_NODE = 'Montar Transcricao';
const META_NODE = 'Filtrar Eventos Validos';

function safeParse(jsonStr) {
  if (typeof jsonStr !== 'string') return jsonStr;
  const s = jsonStr.trim();
  if (!s) return null;
  try { return JSON.parse(s); } catch(e) {
    const a = s.indexOf('{'), b = s.lastIndexOf('}');
    if (a >= 0 && b > a) try { return JSON.parse(s.slice(a, b+1)); } catch(_) {}
    return null;
  }
}

function toNum(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

let tabItems = [];
try { tabItems = $items(TAB_NODE, 0) || []; } catch(e) { tabItems = [items[0]]; }

let convItem = {};
try { convItem = $items(CONV_NODE, 0)?.[0]?.json || {}; } catch(e) {}

let metaItem = {};
try { metaItem = $items(META_NODE, 0)?.[0]?.json || {}; } catch(e) {}

const conversa_bruta = convItem.conversa_bruta || '';
const lead_nome = metaItem.lead_nome || '';
const lead_telefone = metaItem.lead_telefone || '';
const lead_id = metaItem.lead_id || null;
const chat_ids = metaItem.chat_ids || [];
const chat_id = chat_ids[0] || '';

const results = tabItems.map((tItem) => {
  const tj = tItem?.json ?? {};
  const raw = tj.output ?? tj.text ?? tj.response ?? tj.result ?? tj.content ?? '';
  const parsed = safeParse(raw) || safeParse(tj) || {};

  return {
    json: {
      consultor: parsed.consultor || '',
      lead_nome: lead_nome,
      lead_telefone: lead_telefone,
      lead_id: lead_id,
      chat_id: chat_id,
      feedback: parsed.feedback || '',
      ponto_positivo: parsed.ponto_positivo || '',
      ponto_negativo: parsed.ponto_negativo || '',
      tempo_medio_resposta: parsed.tempo_medio_resposta || '',
      tempo_primeira_resposta: parsed.tempo_primeira_resposta || '',
      tempo_atendimento: parsed.tempo_atendimento || '',
      nv1: parsed.nivel_1 || '',
      nv2: parsed.nivel_2 || '',
      nv3: parsed.nivel_3 || '',
      nota_atendimento: toNum(parsed.nota_atendimento),
      nota_abordagem: toNum(parsed.nota_abordagem),
      nota_conhecimento_produto: toNum(parsed.nota_conhecimento_produto),
      interesse: parsed.interesse || '',
      status_lead: parsed.status_lead || '',
      objecoes: parsed.objecoes || '',
      conversa: conversa_bruta
    }
  };
});

return results;
